import{_ as p,c as t}from"./app.90a21e26.js";const r={},o=t('<h1 id="\u7B54\u7591\u89E3\u60D1\u7B2C\u4E8C\u671F" tabindex="-1"><a class="header-anchor" href="#\u7B54\u7591\u89E3\u60D1\u7B2C\u4E8C\u671F" aria-hidden="true">#</a> \u7B54\u7591\u89E3\u60D1\u7B2C\u4E8C\u671F</h1><p>\u4F60\u597D\uFF0C\u6211\u662F\u8339\u70B3\u665F\u3002</p><p>\u4ECA\u5929\u8FD9\u7BC7\u6587\u7AE0\u662F\u201C\u7B54\u7591\u89E3\u60D1\u201D\u7CFB\u5217\u6587\u7AE0\u7684\u7B2C\u4E8C\u671F\uFF0C\u6211\u8FD8\u662F\u9009\u53D6\u4E86\u4E94\u4E2A\u95EE\u9898\u3002\u8FD9\u4E94\u4E2A\u95EE\u9898\u6765\u81EA\u4E8E\u7B2C 6~11 \u7BC7\u8FD9 6 \u7BC7\u6587\u7AE0\uFF0C\u5176\u4E2D\u7B2C 9 \u548C\u7B2C 10 \u7BC7\u8FD9\u4E24\u7BC7\u6587\u7AE0\u4E2D\u7684\u4E24\u4E2A\u95EE\u9898\u88AB\u6211\u5408\u5E76\u4E3A\u4E86\u4E00\u4E2A\u95EE\u9898\uFF0C\u5E76\u4E14\u6211\u4F1A\u9488\u5BF9\u8FD9\u4E2A\u95EE\u9898\uFF0C\u518D\u6B21\u4E3A\u4F60\u7B80\u5355\u68B3\u7406\u4E00\u6761\u5B66\u4E60\u8DEF\u5F84\u3002</p><p>\u7136\u540E\uFF0C\u6211\u8FD8\u4F1A\u9009\u62E9\u8FD9 6 \u7BC7\u6587\u7AE0\u4E0B\u7684\u7CBE\u5F69\u7559\u8A00\uFF0C\u4E3A\u4F60\u7A0D\u4F5C\u89E3\u7B54\u3001\u5206\u6790\u3002</p><p>\u5728\u8FD9\u7BC7\u6587\u7AE0\u4E2D\uFF0C\u6211\u4F9D\u65E7\u4E3A\u4F60\u6DFB\u52A0\u4E86\u6BCF\u7BC7\u6587\u7AE0\u7684\u94FE\u63A5\uFF0C\u5E76\u7528\u4E00\u53E5\u8BDD\u6982\u62EC\u4E86\u8FD9\u7BC7\u6587\u7AE0\u7684\u4E3B\u8981\u5185\u5BB9\uFF0C\u4F60\u4E5F\u53EF\u4EE5\u518D\u6B21\u56DE\u5230\u8FD9\u7BC7\u6587\u7AE0\u4E2D\uFF0C\u56DE\u5FC6\u4E00\u4E0B\u7B2C\u4E00\u6B21\u9605\u8BFB\u540E\u7684\u60F3\u6CD5\uFF0C\u770B\u770B\u7B2C\u4E8C\u6B21\u9605\u8BFB\u53C8\u6709\u4E86\u54EA\u4E9B\u65B0\u7684\u611F\u60F3\u3002\u6B22\u8FCE\u4F60\u7EE7\u7EED\u7ED9\u6211\u7559\u8A00\uFF0C\u6211\u4ECD\u5728\u5173\u6CE8\u7740\u4F60\u7684\u95EE\u9898\u3001\u53CD\u9988\uFF0C\u5E0C\u671B\u53EF\u4EE5\u4E3A\u4F60\u63D0\u4F9B\u66F4\u591A\u7684\u5E2E\u52A9\u3002</p><p>\u73B0\u5728\uFF0C\u6211\u4EEC\u5C31\u5F00\u59CB\u4ECA\u5929\u7684\u4E94\u4E2A\u95EE\u9898\u5427\u3002</p><p><strong>\u95EE\u9898\u4E00\uFF1A\u4F60\u5728\u4F7F\u7528\u4EE3\u7801\u8986\u76D6\u7387\u5DE5\u5177\u7684\u65F6\u5019\uFF0C\u9047\u5230\u8FC7\u54EA\u4E9B\u201C\u5751\u201D\uFF1F</strong></p><p>\u5728\u4E13\u680F\u7B2C 6 \u7BC7\u6587\u7AE0\u300A\u4F60\u771F\u7684\u61C2\u6D4B\u8BD5\u8986\u76D6\u7387\u5417\uFF1F\u300B\u4E2D\uFF0C\u6211\u9488\u5BF9\u4EE3\u7801\u8986\u76D6\u7387\u8FD9\u4E2A\u4E3B\u9898\uFF0C\u548C\u4F60\u5206\u4EAB\u4E86\u4EE3\u7801\u8986\u76D6\u7387\u7684\u7684\u4EF7\u503C\u3001\u5C40\u9650\u6027\uFF0C\u5E76\u7ED3\u5408 JaCoCo \u5206\u6790\u4E86\u4EE3\u7801\u8986\u76D6\u7387\u5DE5\u5177\u7684\u5B9E\u73B0\u539F\u7406\u3002\u8FD9\u4E5F\u662F\u8FD9\u4E2A\u4E13\u680F\u4E2D\u7B2C\u4E00\u7BC7\u4E3A\u4F60\u8BB2\u89E3\u67D0\u79CD\u6D4B\u8BD5\u5DE5\u5177\u5B9E\u73B0\u539F\u7406\u7684\u6587\u7AE0\uFF0C\u5E0C\u671B\u4F60\u53EF\u4EE5\u8BA4\u771F\u4F53\u4F1A\u3002</p><p>\u901A\u8FC7\u9605\u8BFB\u8FD9\u7BC7\u6587\u7AE0\uFF0C\u6211\u5E0C\u671B\u4F60\u56DE\u987E\u4E00\u4E0B\u66FE\u7528\u8FC7\u7684\u4EE3\u7801\u8986\u76D6\u7387\u5DE5\u5177\uFF0C\u5E76\u8BF4\u8BF4\u4F60\u7684\u4F7F\u7528\u611F\u53D7\u548C\u9047\u5230\u7684\u201C\u5751\u201D\u3002</p><p>\u7559\u8A00\u4E2D\uFF0C\u6211\u4E5F\u770B\u5230\u4E86\u4E00\u4E9B\u7559\u8A00\u5F88\u7CBE\u5F69\uFF0C\u63D0\u5230\u4E86\u81EA\u5DF1\u4F7F\u7528\u4EE3\u7801\u8986\u76D6\u7387\u5DE5\u5177\u7684\u4E00\u4E9B\u5B9E\u8DF5\u3002\u6240\u4EE5\uFF0C\u4E5F\u5F88\u611F\u8C22\u4F60\u4EEC\u7684\u5206\u4EAB\u3002</p><p>\u63A5\u4E0B\u6765\uFF0C\u6211\u518D\u548C\u4F60\u5206\u4EAB\u4E0B\uFF0C\u5728\u4F7F\u7528\u4EE3\u7801\u8986\u76D6\u7387\u5DE5\u5177\u65F6\u53EF\u80FD\u9762\u4E34\u7684\u4E24\u4E2A\u6700\u5927\u7684\u95EE\u9898\uFF1A</p><ol><li><strong>\u6D4B\u8BD5\u8986\u76D6\u7387\u8D8A\u5F80\u540E\u8D8A\u96BE\u3002</strong></li></ol><p>\u7EDF\u8BA1\u4EE3\u7801\u8986\u76D6\u7387\u7684\u6839\u672C\u76EE\u7684\u662F\uFF0C\u6307\u5BFC\u7528\u6237\u7684\u6D4B\u8BD5\u7528\u4F8B\u8BBE\u8BA1\u3002\u4E5F\u5C31\u662F\u8BF4\uFF0C\u6211\u4EEC\u8981\u901A\u8FC7\u4EE3\u7801\u8986\u76D6\u7387\u7684\u7ED3\u679C\u53BB\u53D1\u73B0\u54EA\u4E9B\u4EE3\u7801\u6CA1\u6709\u88AB\u6267\u884C\u5230\uFF0C\u4EE5\u6B64\u4E3A\u4F9D\u636E\u518D\u53BB\u8BBE\u8BA1\u6709\u9488\u5BF9\u6027\u7684\u6D4B\u8BD5\u7528\u4F8B\u3002</p><p>\u5728\u8FD9\u4E2A\u8FC7\u7A0B\u4E2D\uFF0C\u4F60\u4F1A\u53D1\u73B0\u524D\u671F\u8FBE\u5230\u4E00\u4E2A\u4E0D\u9519\u7684\u8986\u76D6\u7387\u6307\u6807\uFF08\u6BD4\u5982 70%\uFF09\u8FD8\u662F\u6BD4\u8F83\u5BB9\u6613\u7684\uFF0C\u4F46\u662F\u8D8A\u5F80\u540E\u5C31\u8D8A\u96BE\u63D0\u9AD8\u4E86\u3002</p><p>\u56E0\u4E3A\uFF0C\u540E\u671F\u6CA1\u6709\u8986\u76D6\u5230\u7684\u4EE3\u7801\u5F80\u5F80\u90FD\u662F\u4E00\u4E9B\u51FA\u9519\u5F02\u5E38\u5206\u652F\u7684\u5904\u7406\uFF0C\u4E3A\u4E86\u80FD\u591F\u8986\u76D6\u8FD9\u90E8\u5206\u5185\u5BB9\uFF0C\u5F80\u5F80\u9700\u8981\u6784\u9020\u7279\u6B8A\u7684\u6570\u636E\u548C\u73AF\u5883\u3002\u5F88\u591A\u65F6\u5019\uFF0C\u8FD9\u4E9B\u6570\u636E\u548C\u73AF\u5883\u5E76\u4E0D\u597D\u5F97\u5230\uFF0C\u5C31\u4E0D\u5F97\u4E0D\u91C7\u7528\u5404\u79CD Mock \u7684\u624B\u6BB5\u6765\u5B9E\u73B0\u3002</p><p>\u56E0\u6B64\uFF0C\u5728\u5B9E\u9645\u9879\u76EE\u4E2D\uFF0C\u5230\u5E95\u8981\u4E0D\u8981\u4E00\u5B9A\u5230\u8FBE\u5F88\u9AD8\u7684\u8986\u76D6\u7387\uFF0C\u5C31\u5E94\u8BE5\u6839\u636E\u9879\u76EE\u60C5\u51B5\u7ED3\u5408\u98CE\u9669\u9A71\u52A8\u7684\u6982\u5FF5\u6765\u7EFC\u5408\u5206\u6790\u4E86\u3002</p><ol start="2"><li><strong>\u63A8\u884C\u4EE3\u7801\u8986\u76D6\u7387\u7684\u521D\u671F\u9636\u6BB5\uFF0C\u5F88\u96BE\u8981\u6C42\u5F88\u9AD8\u7684\u8986\u76D6\u7387\u6307\u6807\u3002</strong></li></ol><p>\u4EE3\u7801\u8986\u76D6\u7387\u7684\u6311\u6218\u5E76\u4E0D\u662F\u6765\u81EA\u4E8E\u6280\u672F\u672C\u8EAB\uFF0C\u800C\u662F\u6765\u81EA\u4E8E\u7BA1\u7406\u3002\u5F88\u591A\u516C\u53F8\u5728\u521A\u521A\u63A8\u884C\u8986\u76D6\u7387\u7EDF\u8BA1\u7684\u65F6\u5019\uFF0C\u4F1A\u53D1\u73B0\u5404\u4E2A\u6A21\u5757\u548C\u9879\u76EE\u7684\u8986\u76D6\u7387\u666E\u904D\u8F83\u4F4E\uFF0C\u6709\u4E9B\u751A\u81F3\u8FD8\u4E0D\u5230 20%\u3002\u8FD9\u65F6\uFF0C\u6211\u4EEC\u5C31\u4E0D\u5E94\u8BE5\u4F9D\u9760\u884C\u653F\u624B\u6BB5\u6765\u5F3A\u884C\u89C4\u5B9A\u9AD8\u7684\u4EE3\u7801\u8986\u76D6\u7387\u3002</p><p>\u56E0\u4E3A\u8FD9\u4F1A\u5728\u77ED\u65F6\u95F4\u5185\u589E\u52A0\u5F88\u591A\u5DE5\u4F5C\uFF0C\u4E00\u6765\u4F1A\u5F15\u8D77\u5F00\u53D1\u4EBA\u5458\u7684\u62B5\u89E6\u4E0E\u53CD\u611F\uFF0C\u4E8C\u6765\u4F1A\u803D\u8BEF\u9879\u76EE\u672C\u8EAB\u7684\u8FDB\u5EA6\u3002\u6B64\u65F6\u6700\u597D\u7684\u505A\u6CD5\u662F\u91C7\u7528\u6301\u7EED\u6539\u8FDB\u7684\u7B56\u7565\uFF0C\u4E5F\u5C31\u662F\u968F\u7740\u8FED\u4EE3\u66F4\u65B0\uFF0C\u4EE3\u7801\u8986\u76D6\u7387\u4E0D\u5141\u8BB8\u51FA\u73B0\u4E0B\u964D\u7684\u8D8B\u52BF\uFF0C\u81F3\u5C11\u4FDD\u6301\u6301\u5E73\u6216\u8005\u9010\u6E10\u589E\u957F\u7684\u6001\u52BF\u3002</p><p><strong>\u95EE\u9898\u4E8C\uFF1A\u4F60\u5728\u586B\u5199\u8F6F\u4EF6\u7F3A\u9677\u62A5\u544A\u65F6\uFF0C\u8FD8\u6709\u54EA\u4E9B\u597D\u7684\u5B9E\u8DF5\u503C\u5F97\u5206\u4EAB\u5462\uFF1F</strong></p><p>\u5728\u4E13\u680F\u7B2C 7 \u7BC7\u6587\u7AE0\u300A\u5982\u4F55\u9AD8\u6548\u586B\u5199\u8F6F\u4EF6\u7F3A\u9677\u62A5\u544A\uFF1F\u300B\u4E2D\uFF0C\u6211\u5206\u4EAB\u4E86\u60F3\u8981\u628A\u53D1\u73B0\u7684\u7F3A\u9677\u51C6\u786E\u65E0\u6B67\u4E49\u5730\u8868\u8FBE\u6E05\u695A\uFF0C\u4E00\u4EFD\u9AD8\u6548\u7684\u8F6F\u4EF6\u7F3A\u9677\u62A5\u544A\u5E94\u8BE5\u5305\u62EC\u7684\u5185\u5BB9\uFF0C\u4EE5\u53CA\u9700\u8981\u6CE8\u610F\u7684\u95EE\u9898\u3002</p><p>\u5728\u8FD9\u7BC7\u6587\u7AE0\u6700\u540E\uFF0C\u6211\u5E0C\u671B\u4F60\u5206\u4EAB\u4E00\u4E0B\u81EA\u5DF1\u5728\u586B\u5199\u8F6F\u4EF6\u7F3A\u9677\u62A5\u544A\u65F6\uFF0C\u8FD8\u6709\u54EA\u4E9B\u597D\u7684\u5B9E\u8DF5\u3002</p><p>\u5728\u8FD9\u91CC\uFF0C\u6211\u60F3\u518D\u548C\u4F60\u5206\u4EAB\u53E6\u5916\u4E00\u4E2A\u89C2\u70B9\u3002\u4F60\u5728\u5B9E\u9645\u63D0\u4EA4\u8F6F\u4EF6\u7F3A\u9677\u7684\u65F6\u5019\uFF0C\u6709\u6CA1\u6709\u611F\u89C9\u8FD9\u4E2A\u8FC7\u7A0B\u5F88\u7E41\u7410\u3002\u5BF9\u4E8E\u7F3A\u9677\u7684\u91CD\u73B0\u89C4\u5F8B\u548C\u6B65\u9AA4\u9700\u8981\u505A\u5F88\u591A\u5C1D\u8BD5\uFF0C\u7136\u540E\u5199\u6587\u6863\u65F6\u8FD8\u6709\u5F88\u591A\u5DE5\u4F5C\u91CF\uFF0C\u6BD4\u5982\u9700\u8981\u8003\u8651\u63AA\u8F9E\u548C\u8BED\u53E5\u7684\u7EC4\u7EC7\uFF0C\u8FD9\u5F80\u5F80\u4F1A\u82B1\u8D39\u4F60\u4E0D\u5C11\u65F6\u95F4\u3002\u90A3\u6709\u6CA1\u6709\u4EC0\u4E48\u597D\u65B9\u6CD5\u53EF\u4EE5\u51CF\u5C11\u5199\u6587\u6863\u7684\u5DE5\u4F5C\u91CF\u5417\uFF1F</p><p>\u5176\u5B9E\uFF0C\u5BF9\u4E8E\u4F20\u7EDF\u8F6F\u4EF6\u7684\u5F00\u53D1\u6D41\u7A0B\u6765\u8BB2\uFF0C\u8FD9\u79CD\u91CD\u91CF\u7EA7\u7684\u7F3A\u9677\u62A5\u544A\u662F\u5FC5\u987B\u7684\u3002\u7279\u522B\u662F\u5BF9\u4E8E\u4E00\u4E9B\u5927\u516C\u53F8\u6765\u8BF4\uFF0C\u5F00\u53D1\u4EBA\u5458\u548C\u6D4B\u8BD5\u4EBA\u5458\u53EF\u80FD\u6563\u5E03\u5728\u5168\u7403\u4E0D\u540C\u65F6\u533A\u7684\u5730\u57DF\uFF0C\u8FD9\u79CD\u4E25\u683C\u7684\u7F3A\u9677\u6587\u6863\u5C31\u5F88\u6709\u5FC5\u8981\u4E86\u3002</p><p>\u4F46\u662F\uFF0C\u73B0\u5728\u7684\u5F88\u591A\u4E92\u8054\u7F51\u4F01\u4E1A\uFF0C\u5C24\u5176\u662F\u56FD\u5185\u7684\u4E92\u8054\u7F51\u4F01\u4E1A\uFF0C\u6240\u6709\u7684\u5DE5\u7A0B\u6280\u672F\u4EBA\u5458\u90FD\u5728\u4E00\u4E2A\u529E\u516C\u5BA4\uFF0C\u800C\u4E14\u666E\u904D\u91C7\u7528\u654F\u6377\u5F00\u53D1\u7684\u6A21\u5F0F\uFF0C\u6B64\u65F6\u9762\u5BF9\u9762\u5730\u6C9F\u901A\u8F6F\u4EF6\u7F3A\u9677\u7684\u6548\u679C\u5C06\u8FDC\u8FDC\u597D\u4E8E\u6587\u6863\u63CF\u8FF0\uFF0C\u800C\u7F3A\u9677\u62A5\u544A\u672C\u8EAB\u7684\u4F5C\u7528\u4E5F\u4F1A\u9000\u5316\u6210\u4E00\u6761\u7B80\u5355\u7684\u8BB0\u5F55\u3002</p><p>\u6240\u4EE5\uFF0C<strong>\u7F3A\u9677\u62A5\u544A\u7684\u8BE6\u7EC6\u7A0B\u5EA6\u5E94\u8BE5\u5728\u5F88\u5927\u7A0B\u5EA6\u4E0A\u53D6\u51B3\u4E8E\u56E2\u961F\u7279\u5F81</strong>\u3002</p><p>\u53E6\u5916\uFF0C\u6211\u53D1\u73B0\u8BFB\u8005\u5728\u6587\u7AE0\u7684\u7559\u8A00\u4E2D\u4E5F\u63D0\u51FA\u4E86\u5F88\u591A\u5EFA\u8BBE\u6027\u7684\u65B9\u6CD5\u3002\u6BD4\u5982\uFF0C\u4E0B\u9762\u8FD9\u4F4D\u6635\u79F0\u4E3A\u201C\u536B\u5BA3\u5B89\u201D\u7684\u8BFB\u8005\uFF0C\u63D0\u51FA\u4E86\u8BA9\u5F00\u53D1\u4EBA\u5458\u4E3B\u52A8\u6765\u8BA4\u9886\u7F3A\u9677\u7684\u65B9\u5F0F\u3002\u5982\u679C\u8BF4\u6240\u6709\u7684\u5F00\u53D1\u4EBA\u5458\u90FD\u5177\u6709\u5F88\u5F3A\u7684\u8D23\u4EFB\u5FC3\uFF0C\u540C\u65F6\u7CFB\u7EDF\u89C4\u6A21\u4E5F\u4E0D\u662F\u592A\u5927\uFF0C\u6216\u8005\u8BF4\u62A5\u544A\u7684\u7F3A\u9677\u6570\u91CF\u4E0D\u662F\u5F88\u591A\u7684\u60C5\u51B5\u4E0B\uFF0C\u8FD9\u7684\u786E\u662F\u89E3\u51B3\u95EE\u9898\u7684\u4E00\u4E2A\u597D\u601D\u8DEF\u3002\u4F46\u662F\uFF0C\u5F53\u56E2\u961F\u89C4\u6A21\u6BD4\u8F83\u5927\uFF0C\u7F3A\u9677\u6570\u91CF\u4E5F\u6BD4\u8F83\u591A\u7684\u65F6\u5019\uFF0C\u8981\u6C42\u6BCF\u4E2A\u5F00\u53D1\u4EBA\u5458\u90FD\u53BB\u6328\u4E2A\u67E5\u770B\u6240\u6709\u7F3A\u9677\u7684\u6548\u7387\u5C31\u4F1A\u5F88\u4F4E\u3002</p><p><img src="https://static001.geekbang.org/resource/image/18/03/18b02affdd921cdf2b41347a28a03a03.png" alt=""></p><p>\u90A3\u4E48\uFF0C\u5728\u8FD9\u79CD\u60C5\u51B5\u4E0B\uFF0C\u6211\u4EEC\u662F\u5426\u6709\u66F4\u597D\u7684\u65B9\u6CD5\u6765\u89E3\u51B3\u8FD9\u4E2A\u95EE\u9898\u5462\uFF1F\u7B54\u6848\u5C31\u662F\uFF0C\u91C7\u7528\u57FA\u4E8E AI \u548C\u673A\u5668\u5B66\u4E60\u7684\u7F3A\u9677\u5206\u7C7B\u65B9\u6CD5\u3002\u6211\u4EEC\u53EF\u4EE5\u901A\u8FC7\u7F3A\u9677\u7684\u7279\u5F81\u503C\u63D0\u53D6\uFF0C\u5E76\u7ED3\u5408\u5206\u7C7B\u7B97\u6CD5\u5BF9\u7F3A\u9677\u5E94\u8BE5\u5F52\u5C5E\u7684\u56E2\u961F\u8FDB\u884C\u81EA\u52A8\u5206\u7C7B\u3002</p><p>\u5728 eBay \u7684\u81EA\u52A8\u5316\u6D4B\u8BD5\u4F53\u7CFB\u4E2D\uFF0C\u5C31\u6709\u4E13\u95E8\u7684\u7CFB\u7EDF\u5BF9\u5931\u8D25\u7528\u4F8B\u548C\u7F3A\u9677\u505A\u81EA\u52A8\u8FDB\u884C\u5206\u7C7B\u3002</p><p><strong>\u95EE\u9898\u4E09\uFF1A\u4F60\u89C9\u5F97\u5728\u5B9E\u9645\u5DE5\u7A0B\u9879\u76EE\u4E2D\uFF0C\u4E00\u4EFD\u9AD8\u6548\u7684\u6D4B\u8BD5\u8BA1\u5212\u5E94\u8BE5\u5305\u62EC\u54EA\u4E9B\u5185\u5BB9\uFF1F</strong></p><p>\u5728\u7B2C 8 \u7BC7\u6587\u7AE0\u300A\u4EE5\u7EC8\u4E3A\u59CB\uFF0C\u5982\u4F55\u624D\u80FD\u505A\u597D\u6D4B\u8BD5\u8BA1\u5212\uFF1F\u300B\u4E2D\uFF0C\u6211\u548C\u4F60\u5206\u4EAB\u4E86\u867D\u7136\u5728\u654F\u6377\u5F00\u53D1\u6A21\u5F0F\u4E0B\uFF0C\u8F6F\u4EF6\u6D4B\u8BD5\u4E0D\u518D\u5C40\u9650\u4E8E\u539A\u91CD\u7684\u3001\u6B63\u5F0F\u7684\u8BA1\u5212\u6587\u6863\uFF0C\u4F46\u662F\u6D4B\u8BD5\u8BA1\u5212\u7684\u91CD\u8981\u6027\u4E1D\u6BEB\u6CA1\u6709\u53D1\u751F\u53D8\u5316\u3002\u4E00\u4EFD\u6210\u529F\u7684\u6D4B\u8BD5\u8BA1\u5212\uFF0C\u4F9D\u65E7\u5FC5\u987B\u8981\u6E05\u695A\u5730\u63CF\u8FF0\u51FA\u6D4B\u8BD5\u8303\u56F4\u3001\u6D4B\u8BD5\u7B56\u7565\u3001\u6D4B\u8BD5\u8D44\u6E90\u3001\u6D4B\u8BD5\u8FDB\u5EA6\u548C\u6D4B\u8BD5\u98CE\u9669\u9884\u4F30\u8FD9\u4E94\u4E2A\u6700\u91CD\u8981\u7684\u65B9\u9762\u3002</p><p>\u800C\u5728\u8BFB\u5B8C\u8FD9\u7BC7\u6587\u7AE0\u4E4B\u540E\uFF0C\u6211\u5E0C\u671B\u4F60\u601D\u8003\u7684\u662F\uFF0C\u5728\u4E00\u4EFD\u6D4B\u8BD5\u8BA1\u5212\u4E2D\uFF0C\u9664\u4E86\u8FD9\u4E94\u4E2A\u6700\u6700\u5173\u952E\u7684\u5185\u5BB9\u5916\uFF0C\u4F60\u89C9\u5F97\u5728\u5B9E\u9645\u5DE5\u7A0B\u9879\u76EE\u4E2D\u8FD8\u9700\u8981\u518D\u589E\u52A0\u7684\u5185\u5BB9\uFF0C\u4EE5\u53CA\u662F\u4E0D\u662F\u6240\u6709\u7684\u9879\u76EE\u90FD\u9700\u8981\u6709\u5F88\u8BE6\u5B9E\u7684\u6D4B\u8BD5\u8BA1\u5212\u3002</p><p>\u5176\u5B9E\u5F88\u591A\u65F6\u5019\uFF0C \u4F60\u4F1A\u53D1\u73B0\u8BA1\u5212\u7684\u901F\u5EA6\u8FDC\u8FDC\u8D76\u4E0D\u4E0A\u53D8\u5316\uFF0C\u5C24\u5176\u662F\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u5F00\u53D1\u3002\u5C31\u50CF\u4E0B\u9762\u8FD9\u4E24\u4F4D\u7528\u6237\u5728\u7559\u8A00\u4E2D\u63CF\u8FF0\u7684\u73B0\u8C61\uFF0C\u76F8\u4FE1\u4F60\u5728\u5B9E\u9645\u7684\u5DE5\u4F5C\u4E2D\u4E00\u5B9A\u9047\u5230\u8FC7\u7C7B\u4F3C\u7684\u573A\u666F\u3002</p><p><img src="https://static001.geekbang.org/resource/image/01/fc/014a7d773a20633c499a4f9bc45310fc.png" alt=""></p><p><img src="https://static001.geekbang.org/resource/image/ab/1b/ab3f85cc62c291c45190adc9006ac81b.png" alt=""></p><p>\u6240\u4EE5\uFF0C\u8FD9\u4E2A\u65F6\u5019\uFF0C<strong>\u4F60\u6709\u6CA1\u6709\u53CD\u95EE\u8FC7\u81EA\u5DF1\u4E00\u4E2A\u95EE\u9898\uFF0C\u6B64\u65F6\u6587\u6863\u5316\u7684\u8BE6\u7EC6\u6D4B\u8BD5\u8BA1\u5212\u8FD8\u771F\u7684\u6709\u5FC5\u8981\u5417\uFF1F\u6216\u8005\u8BF4\u6709\u6CA1\u6709\u53EF\u80FD\u91C7\u7528\u8F7B\u91CF\u7EA7\u7684\u6D4B\u8BD5\u8BA1\u5212</strong>\u3002</p><p>\u9996\u5148\uFF0C\u8F7B\u91CF\u7EA7\u7684\u6D4B\u8BD5\u8BA1\u5212\u5E76\u4E0D\u662F\u8BF4\u6CA1\u6709\u8BA1\u5212\uFF0C\u800C\u662F\u6307\u8BA1\u5212\u7684\u6587\u6863\u5316\u8868\u73B0\u5F62\u5F0F\u5E94\u8BE5\u5C3D\u53EF\u80FD\u7B80\u5355\uFF0C\u53EA\u662F\u7528\u4E00\u4E9B\u5173\u952E\u8BCD\u6765\u63CF\u8FF0\u7EB2\u9886\u6027\u7684\u4E1C\u897F\u3002\u8FD9\u6837\u505A\uFF0C\u4E00\u6765\u53EF\u4EE5\u964D\u4F4E\u6D4B\u8BD5\u8BA1\u5212\u672C\u8EAB\u7684\u5199\u4F5C\u65F6\u95F4\uFF1B\u4E8C\u6765\u5F53\u6D4B\u8BD5\u8BA1\u5212\u7531\u4E8E\u5404\u79CD\u539F\u56E0\u53D1\u751F\u53D8\u5316\u7684\u65F6\u5019\uFF0C\u4E5F\u53EF\u4EE5\u975E\u5E38\u5FEB\u901F\u7075\u6D3B\u5730\u8FDB\u884C\u4FEE\u6539\u548C\u66F4\u65B0\u3002</p><p>\u5176\u5B9E\uFF0C\u76EE\u524D\u7684\u654F\u6377\u5F00\u53D1\u6A21\u5F0F\uFF08\u6BD4\u5982 Scrum \u6A21\u5F0F\uFF09\u4E0B\u7684\u6D4B\u8BD5\u8BA1\u5212\u5C31\u4F1A\u5728\u6BCF\u4E2A Sprint \u6700\u5F00\u59CB\u7684\u65F6\u5019\uFF0C\u4EE5\u975E\u5E38\u8F7B\u91CF\u7EA7\u7684\u65B9\u5F0F\u6765\u786E\u5B9A\u6D4B\u8BD5\u8BA1\u5212\uFF0C\u6709\u4E9B\u65F6\u5019\u751A\u81F3\u53EF\u4EE5\u6CA1\u6709\u6587\u6863\u5316\u7684\u6D4B\u8BD5\u8BA1\u5212\u3002\u8FD9\u65F6\uFF0C\u5173\u4E8E\u6D4B\u8BD5\u8303\u56F4\u3001\u6D4B\u8BD5\u7B56\u7565\u548C\u6D4B\u8BD5\u8BBE\u8BA1\u4E4B\u7C7B\u7684\u5185\u5BB9\u90FD\u5728\u6D4B\u8BD5\u4EBA\u5458\u7684\u8111\u5B50\u4E2D\u3002</p><p>\u6CE8\u610F\uFF0C\u8FD9\u65F6\u5019\u867D\u7136\u6CA1\u6709\u4E66\u9762\u7684\u6D4B\u8BD5\u8BA1\u5212\uFF0C\u4F46\u5E76\u4E0D\u4EE3\u8868\u8BF4\u6CA1\u6709\u6D4B\u8BD5\u8BA1\u5212\u3002</p><p><strong>\u95EE\u9898\u56DB\uFF1A\u8F6F\u4EF6\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u7684\u9AD8\u6548\u8FDB\u9636\u8DEF\u5F84\u662F\u4EC0\u4E48\uFF1F</strong></p><p>\u6211\u5728\u7B2C 9 \u7BC7\u6587\u7AE0\u300A\u8F6F\u4EF6\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u7684\u6838\u5FC3\u7ADE\u4E89\u529B\u662F\u4EC0\u4E48\uFF1F\u300B\u548C\u7B2C 10 \u7BC7\u6587\u7AE0\u300A\u8F6F\u4EF6\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u9700\u8981\u638C\u63E1\u7684\u975E\u6D4B\u8BD5\u77E5\u8BC6\u6709\u54EA\u4E9B\uFF1F\u300B\u4E2D\uFF0C\u5206\u522B\u548C\u4F60\u5206\u4EAB\u4E86\u4E00\u4E2A\u8F6F\u4EF6\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u9700\u8981\u5177\u5907\u7684\u6838\u5FC3\u7ADE\u4E89\u529B\uFF0C\u4EE5\u53CA\u9700\u8981\u638C\u63E1\u7684\u975E\u6D4B\u8BD5\u4E13\u4E1A\u77E5\u8BC6\u3002\u770B\u5230\u8FD9\u4E24\u7BC7\u6587\u7AE0\u540E\u9762\uFF0C\u6709\u5F88\u591A\u7528\u6237\u7559\u8A00\u8BF4\uFF1A\u89C9\u5F97\u5F88\u8FF7\u832B\uFF0C\u6293\u4E0D\u4F4F\u81EA\u5DF1\u8981\u91CD\u70B9\u57F9\u517B\u7684\u80FD\u529B\u3001\u8981\u600E\u4E48\u5FEB\u901F\u5B66\u4E60\u3002</p><p>\u867D\u7136\u4ECA\u5E74 7 \u6708 6 \u65E5\u6211\u5728\u6781\u5BA2\u65F6\u95F4\u505A\u76F4\u64AD\u65F6\u56DE\u7B54\u8FC7\u8FD9\u4E2A\u95EE\u9898\uFF0C\u4F46\u8FD9\u91CC\u4E3A\u4E86\u5E2E\u52A9\u4F60\u5FEB\u901F\u627E\u5230\u4E00\u6761\u9002\u5408\u81EA\u5DF1\u7684\u9053\u8DEF\uFF0C\u6211\u5C31\u518D\u7B80\u5355\u4E3A\u4F60\u68B3\u7406\u4E0B\u3002</p><p>\u9996\u5148\uFF0C\u6211\u628A\u5728\u8F6F\u4EF6\u6D4B\u8BD5\u5C97\u4F4D\u4E0A\u5DE5\u4F5C\u4E86 0~5\uFF08\u6216\u8005 0~3\uFF09\u5E74\u7684\u5DE5\u7A0B\u5E08\uFF0C\u5212\u5206\u4E3A\u521D\u7EA7\u6D4B\u8BD5\u4EBA\u3002\u4E3A\u4EC0\u4E48\u6709\u8FD9\u4E2A\u5212\u5206\u5462\uFF1F\u56E0\u4E3A 0-5 \u5E74\u5DE5\u4F5C\u7ECF\u9A8C\u7684\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u5F80\u5F80\u5DE5\u4F5C\u7684\u4E2D\u5FC3\u90FD\u8FD8\u662F\u5728\u8F6F\u4EF6\u4EA7\u54C1\u6D4B\u8BD5\u672C\u8EAB\uFF0C\u8FD8\u6CA1\u6709\u5C06\u6D4B\u8BD5\u4E0A\u5347\u5230\u8D28\u91CF\u5DE5\u7A0B\u7684\u9AD8\u5EA6\u3002\u5F53\u7136\u4E86\uFF0C\u6211\u8FD9\u91CC\u8BF4\u7684\u6D4B\u8BD5\u6307\u7684\u662F\u5E7F\u4E49\u4E0A\u7684\u6D4B\u8BD5\uFF0C\u5305\u62EC\u529F\u80FD\u6D4B\u8BD5\u3001\u81EA\u52A8\u5316\u6D4B\u8BD5\u3001\u6027\u80FD\u6D4B\u8BD5\u7B49\u5404\u4E2A\u65B9\u9762\u3002</p><p>\u7136\u540E\uFF0C\u6211\u628A\u521D\u7EA7\u6D4B\u8BD5\u4EBA\u53EF\u4EE5\u8FDB\u9636\u7684\u65B9\u5411\uFF0C\u5F52\u7EB3\u4E3A\u4E86\u4E09\u7C7B\uFF1A</p><ol><li>\u4E1A\u52A1\u4E13\u5BB6\uFF0C\u4E5F\u5C31\u662F\u4E1A\u52A1\u529F\u80FD\u6D4B\u8BD5\u65B9\u5411\uFF1B</li><li>\u5F00\u53D1\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\uFF0C\u4E5F\u5C31\u662F\u81EA\u52A8\u5316\u6D4B\u8BD5\u65B9\u5411\uFF0C\u6307\u7684\u662F\u628A\u4E1A\u52A1\u529F\u80FD\u7684\u6D4B\u8BD5\u8F6C\u6362\u6210\u81EA\u52A8\u5316\u7684\u811A\u672C\uFF1B</li><li>\u6D4B\u8BD5\u5F00\u53D1\u5DE5\u7A0B\u5E08\uFF0C\u6307\u7684\u662F\u8D1F\u8D23\u5F00\u53D1\u6D4B\u8BD5\u5E73\u53F0\u3001\u5DE5\u5177\uFF0C\u4EE5\u53CA\u670D\u52A1\u3002</li></ol><p>\u63A5\u4E0B\u6765\uFF0C\u6211\u5C31\u7B80\u5355\u603B\u7ED3\u4E0B\uFF0C\u5411\u6BCF\u4E2A\u65B9\u5411\u8FDB\u9636\u7684\u76F8\u5BF9\u9AD8\u6548\u7684\u8DEF\u5F84\u5427\u3002</p><p><strong>\u9996\u5148\uFF0C\u5982\u679C\u4F60\u60F3\u6210\u957F\u4E3A\u4E00\u540D\u4E1A\u52A1\u4E13\u5BB6\u7684\u8BDD\uFF0C\u90A3\u4F60\u5C31\u9700\u8981\u7CBE\u901A\u4E8E\u67D0\u4E00\u9879\u5177\u4F53\u7684\u6D4B\u8BD5\u4E1A\u52A1</strong>\uFF0C\u6BD4\u5982\u8BF4\u7535\u5B50\u5546\u52A1\u7F51\u7AD9\u3001EPR \u7CFB\u7EDF\u548C SAP \u7CFB\u7EDF\u7B49\u7B49\u3002\u8FD9\u6837\u7684\u89D2\u8272\u66F4\u50CF\u662F\u4EA7\u54C1\u7ECF\u7406\uFF0C\u4F60\u9700\u8981\u80FD\u51C6\u786E\u628A\u63E1\u4E1A\u52A1\u4EA7\u54C1\u7684\u5B9A\u4F4D\uFF0C\u4E86\u89E3\u6574\u4E2A\u4E1A\u52A1\u6D41\u7A0B\u7684\u64CD\u4F5C\u3001\u7528\u6237\u7684\u4F7F\u7528\u4E60\u60EF\uFF0C\u4EE5\u53CA\u5982\u4F55\u63D0\u5230\u6574\u4E2A\u4EA7\u54C1\u7684\u8F6C\u5316\u7387\u3002</p><p>\u800C\u8981\u6210\u4E3A\u8FD9\u6837\u7684\u4EBA\uFF0C\u4F60\u9996\u5148\u9700\u8981\u5728\u8BE5\u9886\u57DF\u4E2D\u6709\u8F83\u957F\u65F6\u95F4\u7684\u79EF\u7D2F\uFF0C\u80FD\u591F\u4ECE\u771F\u6B63\u7684\u7EC8\u7AEF\u7528\u6237\u89C6\u89D2\u6765\u4F7F\u7528\u88AB\u6D4B\u8F6F\u4EF6\uFF0C\u80FD\u591F\u5BF9\u8BE5\u8F6F\u4EF6\u5E94\u7528\u9886\u57DF\u7684\u884C\u4E1A\u77E5\u8BC6\u6709\u6BD4\u8F83\u6E05\u695A\u7684\u4E86\u89E3\u3002</p><p>\u4F46\u7CBE\u901A\u4E8E\u67D0\u4E00\u4E2A\u4E1A\u52A1\u9886\u57DF\u7684\u7F3A\u70B9\u662F\uFF0C\u4E00\u65E6\u79BB\u5F00\u4E86\u8FD9\u4E2A\u4E1A\u52A1\u9886\u57DF\uFF0C\u4E4B\u524D\u7684\u4E1A\u52A1\u79EF\u7D2F\u5C31\u6CA1\u7528\u4E86\u3002</p><p><strong>\u5176\u6B21\uFF0C\u5982\u679C\u60F3\u8981\u6210\u957F\u4E3A\u4E00\u540D\u5F00\u53D1\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u7684\u8BDD\uFF0C\u4F60\u5E73\u65F6\u9700\u8981\u79EF\u7D2F\u9AD8\u6548\u7684\u6D4B\u8BD5\u7528\u4F8B\u7EC4\u7EC7\u65B9\u6CD5\u3001\u5BF9\u81EA\u5DF1\u7528\u5230\u7684\u6D4B\u8BD5\u6846\u67B6\u7684\u4F18\u52A3\u52BF\u6709\u6DF1\u5165\u7406\u89E3\uFF0C\u5E76\u5728\u4F7F\u7528\u67D0\u79CD\u6D4B\u8BD5\u5DE5\u5177\u65F6\u8981\u6DF1\u5165\u5230\u5176\u539F\u7406\u7684\u5C42\u9762</strong>\u3002</p><p>\u8FD9\u6837\u7684\u8BDD\uFF0C\u4F60\u5C31\u53EF\u4EE5\u5FEB\u901F\u5177\u5907\u6D4B\u8BD5\u7528\u4F8B\u8BBE\u8BA1\u3001\u6D4B\u8BD5\u6846\u67B6\u9009\u578B\u3001\u7075\u6D3B\u8FD0\u7528\u6D4B\u8BD5\u5DE5\u5177\u7684\u6280\u80FD\u3002\u5E76\u4E14\uFF0C\u4F60\u4E5F\u4F1A\u56E0\u4E3A\u8FD9\u79CD\u957F\u671F\u7684\u201C\u77E5\u5176\u6240\u4EE5\u7136\u201D\u7684\u79EF\u7D2F\uFF0C\u53EF\u4EE5\u4ECE\u5BB9\u5E94\u5BF9\u65B0\u7684\u6280\u672F\u8D8B\u52BF\u3002\u6BD4\u5982\u8BF4\uFF0C\u4F60\u638C\u63E1\u4E86 Selenium 1.0\u30012.0 \u7684\u5B9E\u73B0\u539F\u7406\u540E\uFF0C\u5BF9 API \u6D4B\u8BD5\u7684\u539F\u7406\u4E5F\u5C31\u53EF\u4EE5\u505A\u5230\u89E6\u7C7B\u65C1\u901A\u4E86\u3002</p><p><strong>\u6700\u540E\uFF0C\u5982\u679C\u60F3\u8981\u6210\u957F\u4E3A\u4E00\u540D\u6D4B\u8BD5\u5F00\u53D1\u5DE5\u7A0B\u5E08\u7684\u8BDD\uFF0C\u90A3\u4F60\u9700\u8981\u57F9\u517B\u7684\u662F\u5F00\u53D1\u80FD\u529B\uFF0C\u4EE5\u53CA\u6D4B\u8BD5\u610F\u8BC6</strong>\u3002\u8BF4\u767D\u4E86\uFF0C\u6D4B\u8BD5\u5F00\u53D1\u5DE5\u7A0B\u5E08\uFF0C\u66F4\u50CF\u662F\u4E00\u4E2A\u5F00\u53D1\u4EBA\u5458\uFF0C\u53EA\u4E0D\u8FC7\u9700\u8981\u5728\u7406\u89E3\u6D4B\u8BD5\u4E0A\u4E0B\u6587\u7684\u57FA\u7840\u4E0A\uFF0C\u4E3A\u5176\u4ED6\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u5F00\u53D1\u4E00\u4E9B\u5E73\u53F0\u3001\u5DE5\u5177\u3001\u670D\u52A1\u3002\u8FD9\u65F6\uFF0C\u6211\u5EFA\u8BAE\u7684\u6210\u957F\u8DEF\u5F84\uFF0C\u5C31\u662F\u4E00\u4E2A\u5F00\u53D1\u5DE5\u7A0B\u5E08\u7684\u6210\u957F\u8DEF\u5F84\u4E86\u3002</p><p><strong>\u95EE\u9898\u4E94\uFF1A\u4F60\u89C9\u5F97\u4F60\u73B0\u5728\u56E2\u961F\u91C7\u53D6\u7684\u81EA\u52A8\u5316\u6D4B\u8BD5\u7B56\u7565\uFF0C\u6709\u54EA\u4E9B\u597D\u7684\u5730\u65B9\uFF0C\u53C8\u6709\u54EA\u4E9B\u9700\u8981\u6539\u8FDB\u7684\uFF1F</strong></p><p>\u5728\u7B2C 11 \u7BC7\u6587\u7AE0\u300A\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u6D4B\u8BD5\u7B56\u7565\u5E94\u8BE5\u5982\u4F55\u8BBE\u8BA1\uFF1F\u300B\u4E2D\uFF0C\u6211\u548C\u4F60\u5206\u4EAB\u4E86\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u7279\u6027\u51B3\u5B9A\u4E86\u5B83\u91C7\u7528\u7684\u6D4B\u8BD5\u7B56\u7565\uFF0C\u9075\u5FAA\u7684\u662F\u201C\u91CD\u91CF\u7EA7 API \u6D4B\u8BD5\uFF0C\u8F7B\u91CF\u7EA7 GUI \u6D4B\u8BD5\uFF0C\u8F7B\u91CF\u7EA7\u5355\u5143\u6D4B\u8BD5\u201D\u7684\u539F\u5219\uFF0C\u66F4\u50CF\u662F\u4E00\u4E2A\u83F1\u5F62\u7ED3\u6784\u3002\u8FD9\u4E0E\u4F20\u7EDF\u8F6F\u4EF6\u4EA7\u54C1\u7684\u91D1\u5B57\u5854\u6D4B\u8BD5\u7B56\u7565\u6709\u6240\u533A\u522B\u3002</p><p>\u800C\u5728\u6587\u7AE0\u6700\u540E\uFF0C\u6211\u5E0C\u671B\u4F60\u53EF\u4EE5\u9488\u5BF9\u4F60\u6240\u5728\u516C\u53F8\u91C7\u53D6\u7684\u6D4B\u8BD5\u7B56\u7565\uFF0C\u8C08\u8C08\u81EA\u5DF1\u7684\u770B\u6CD5\u3002</p><p>\u8FD9\u91CC\uFF0C\u6211\u53EF\u4EE5\u7ED9\u4F60\u5206\u4EAB\u4E00\u4E0B eBay \u7684\u81EA\u52A8\u5316\u6D4B\u8BD5\u7B56\u7565\u7684\u6F14\u53D8\u548C\u53D1\u5C55\u8DEF\u5F84\uFF0C\u5E0C\u671B\u53EF\u4EE5\u5E2E\u52A9\u4F60\u7406\u89E3\u4EC0\u4E48\u53EB\u4F5C\u56E0\u5730\u5236\u5B9C\u5730\u9009\u62E9\u548C\u8BBE\u8BA1\u6700\u9002\u5408\u4F60\u7684\u81EA\u52A8\u5316\u6D4B\u8BD5\u7B56\u7565\u3002</p><p>eBay \u5728\u65E9\u671F\u9636\u6BB5\uFF0C\u4E5F\u548C\u73B0\u4ECA\u5927\u591A\u6570\u516C\u53F8\u4E00\u6837\uFF0C\u91C7\u7528\u7684\u662F\u57FA\u4E8E GUI \u6765\u5927\u89C4\u6A21\u5F00\u5C55\u81EA\u52A8\u5316\u6D4B\u8BD5\u3002\u5C24\u5176\u65E9\u671F\u9636\u6BB5\u7684\u7F51\u7AD9\u672C\u8EAB\u8FD8\u4E0D\u662F\u592A\u590D\u6742\uFF0C\u800C\u4E14\u8FD8\u4E0D\u662F\u73B0\u5728\u7684\u5FAE\u670D\u52A1\u67B6\u6784\uFF0C\u6240\u4EE5\u57FA\u4E8E GUI \u7684\u81EA\u52A8\u5316\u6D4B\u8BD5\u5728\u9875\u9762\u5BF9\u8C61\u6A21\u578B\u548C\u4E1A\u52A1\u6D41\u7A0B\u6A21\u578B\u7684\u652F\u6301\u4E0B\uFF0C\u80FD\u591F\u5F88\u597D\u5730\u5B8C\u6210\u4E1A\u52A1\u529F\u80FD\u7684\u9A8C\u8BC1\u548C\u6D4B\u8BD5\u3002</p><p>\u8FD9\u4E2A\u9636\u6BB5\uFF0C\u6211\u4EEC\u5173\u6CE8\u7684\u91CD\u70B9\u662F\u901A\u8FC7 GUI \u5C42\u9762\u7684\u64CD\u4F5C\u6765\u5BF9\u6574\u4E2A\u7F51\u7AD9\u7684\u4E1A\u52A1\u529F\u80FD\u8FDB\u884C\u9A8C\u8BC1\u3002</p><p>\u53EF\u662F\uFF0C\u540E\u6765\u968F\u7740\u4E1A\u52A1\u7684\u4E0D\u65AD\u53D1\u5C55\u4E0E\u58EE\u5927\uFF0C\u57FA\u4E8E GUI \u7684\u6D4B\u8BD5\u7528\u4F8B\u6570\u91CF\u4E0D\u65AD\u589E\u957F\uFF0C\u540C\u65F6\u518D\u52A0\u4E0A\u6D4F\u89C8\u5668\u517C\u5BB9\u6027\u6D4B\u8BD5\u7B49\u7684\u8981\u6C42\uFF0C\u6D4B\u8BD5\u7528\u4F8B\u7684\u6570\u91CF\u8D8A\u6765\u8D8A\u591A\uFF0C\u6D4B\u8BD5\u6267\u884C\u7684\u6548\u7387\u4E5F\u8D8A\u6765\u8D8A\u4F4E\u4E0B\uFF0C\u6240\u4EE5\u5355\u9760 GUI \u6D4B\u8BD5\u5DF2\u7ECF\u5F88\u96BE\u6EE1\u8DB3\u5168\u9762\u6D4B\u8BD5\u7684\u8981\u6C42\u4E86\u3002</p><p>\u518D\u52A0\u4E0A\u7CFB\u7EDF\u67B6\u6784\u672C\u8EAB\u4E5F\u4ECE\u539F\u672C\u7684\u5355\u4F53\u5E94\u7528\u9010\u6E10\u53D1\u5C55\u6210\u4E3A\u4E86\u5FAE\u670D\u52A1\uFF0C\u751A\u81F3\u662F\u670D\u52A1\u7F51\u683C\u7684\u67B6\u6784\u5F62\u5F0F\uFF0C\u540C\u65F6\u666E\u904D\u91C7\u7528\u4E86\u524D\u540E\u7AEF\u5206\u79BB\u7684\u67B6\u6784\u8BBE\u8BA1\uFF0C\u6240\u4EE5\u6B64\u65F6\u7684\u6D4B\u8BD5\u91CD\u70B9\u4E5F\u5C31\u4ECE\u539F\u6765\u4EE5 GUI \u4E3A\u4E3B\u8F6C\u53D8\u6210\u4E86\u4EE5\u540E\u7AEF API \u4E3A\u4E3B\u7684\u9636\u6BB5\u3002</p><p>\u6B64\u65F6 GUI \u6D4B\u8BD5\u53EA\u4F1A\u53BB\u8986\u76D6\u4E00\u4E9B\u6700\u6700\u57FA\u672C\u7684\u4E1A\u52A1\u529F\u80FD\uFF0C\u800C API \u6D4B\u8BD5\u5219\u4F1A\u5173\u6CE8\u5404\u79CD\u53C2\u6570\u7684\u7EC4\u5408\u4EE5\u53CA\u5404\u79CD\u8FB9\u754C\u573A\u666F\u3002</p><p>\u901A\u8FC7\u8FD9\u4E2A\u5B9E\u9645\u7684\u4F8B\u5B50\uFF0C\u6211\u4EEC\u53EF\u4EE5\u770B\u51FA\uFF0C<strong>\u5E76\u4E0D\u5B58\u5728\u4E00\u4E2A\u653E\u4E4B\u56DB\u6D77\u800C\u7686\u51C6\u7684\u81EA\u52A8\u5316\u6D4B\u8BD5\u7B56\u7565\u3002\u6D4B\u8BD5\u7B56\u7565\u7684\u9009\u62E9\uFF0C\u5728\u5F88\u5927\u7A0B\u5EA6\u4E0A\u53D6\u51B3\u4F60\u7684\u6D4B\u8BD5\u8BC9\u6C42\u4EE5\u53CA\u88AB\u6D4B\u7CFB\u7EDF\u672C\u8EAB\u7684\u67B6\u6784\u8BBE\u8BA1</strong>\u3002</p>',63);function s(a,n){return o}var e=p(r,[["render",s],["__file","55.html.vue"]]);export{e as default};
